// ==========================================
// 1. 三元坐标转直角坐标函数 (保持不变)
// ==========================================
const SQRT3_2 = 0.866025;
function toCartesian(ch4, c2h4) {
  // 假设底边长 100
  let x = c2h4 + ch4 / 2;
  let y = ch4 * SQRT3_2;
  return [x, y];
}

// ==========================================
// 2. 定义杜瓦尔三角形区域 (标准 IEC 60599 坐标)
// ==========================================
const zones = [
  { name: 'PD', color: '#B4E1FF', points: [[98, 0, 2], [100, 0, 0], [98, 2, 0]] },
  { name: 'T1', color: '#C1FFC1', points: [[98, 2, 0], [80, 20, 0], [76, 20, 4], [96, 0, 4], [98, 0, 2]] },
  { name: 'T2', color: '#FFFACD', points: [[80, 20, 0], [50, 50, 0], [46, 50, 4], [76, 20, 4]] },
  { name: 'T3', color: '#FFD700', points: [[50, 50, 0], [0, 100, 0], [0, 85, 15], [35, 50, 15], [46, 50, 4]] },
  { name: 'D1', color: '#FFB6C1', points: [[87, 0, 13], [64, 23, 13], [0, 23, 77], [0, 0, 100]] },
  { name: 'D2', color: '#FF69B4', points: [[64, 23, 13], [74, 13, 13], [47, 40, 13], [31, 40, 29], [0, 71, 29], [0, 23, 77]] },
  { name: 'DT', color: '#E6E6FA', points: [[96, 0, 4], [76, 20, 4], [46, 50, 4], [35, 50, 15], [0, 85, 15], [0, 71, 29], [31, 40, 29], [47, 40, 13], [64, 23, 13], [87, 0, 13]] }
];

// ==========================================
// 3. 从 Grafana 数据源动态提取最新值 (终极匹配版)
// ==========================================
let ch4_p = 0, c2h4_p = 0, c2h2_p = 0;

// 1. 获取数据源 (兼容不同版本的插件 API)
const seriesList = (typeof context !== 'undefined' && context.panel && context.panel.data && context.panel.data.series)
  ? context.panel.data.series
  : (typeof data !== 'undefined' && data.series ? data.series : []);

// 💡 调试神器：将数据打印到浏览器控制台
console.log("🚀 Grafana 传入的原始数据结构:", seriesList);

// 2. 暴力遍历提取数据
if (seriesList && seriesList.length > 0) {
  seriesList.forEach(series => {
    if (!series.fields) return;

    series.fields.forEach(field => {
      const name = field.name;
      // 兼容不同的底层数组读取方式
      const vals = field.values.buffer || field.values;

      if (!vals || vals.length === 0) return;

      // 取最新的一条数据 (数组的最后一个值)
      const lastVal = vals[vals.length - 1];

      // 过滤掉无效值
      if (lastVal === null || lastVal === undefined) return;

      // ⚠️ 关键修改：使用 includes 模糊匹配，防止 Grafana 自动追加后缀标签
      if (name.includes('CH4_pct')) ch4_p = lastVal;
      if (name.includes('C2H4_pct')) c2h4_p = lastVal;
      if (name.includes('C2H2_pct')) c2h2_p = lastVal;
    });
  });
}

console.log(`🎯 最终提取用于画点的值 -> CH4: ${ch4_p}, C2H4: ${c2h4_p}, C2H2: ${c2h2_p}`);

const transformerPoint = toCartesian(ch4_p, c2h4_p, c2h2_p);

// ==========================================
// 4. ECharts 配置
