        { name: '60', value: toCartesian(60, 0, 40).map((v, i) => i === 0 ? v - 5 : v) },
        { name: '80', value: toCartesian(80, 0, 20).map((v, i) => i === 0 ? v - 5 : v) },

        // 3. 右侧 C2H4 刻度 (X轴向右平移量从 +3 增大到 +5)
        { name: '20', value: toCartesian(80, 20, 0).map((v, i) => i === 0 ? v + 5 : v) },
        { name: '40', value: toCartesian(60, 40, 0).map((v, i) => i === 0 ? v + 5 : v) },
        { name: '60', value: toCartesian(40, 60, 0).map((v, i) => i === 0 ? v + 5 : v) },
        { name: '80', value: toCartesian(20, 80, 0).map((v, i) => i === 0 ? v + 5 : v) },

        // 4. 底部 C2H2 刻度 (Y轴向下平移量从 -3 增大到 -5)
        { name: '20', value: [80, -5] },
        { name: '40', value: [60, -5] },
        { name: '60', value: [40, -5] },
        { name: '80', value: [20, -5] }
      ]
    },
    // 第四层：实际气体检测数据点 (红点)
    {
      name: '当前状态',
      type: 'scatter',
