}

// ===== 布局计算（调整这里改卡片大小）=====
const W = context.panel.chart.getWidth();
const H = context.panel.chart.getHeight();
const pad = 10;                          // 卡片间距（px）
const cw = (W - pad * 5) * 0.235;      // 比值卡片宽度
const dw = (W - pad * 5) * 0.265;      // 诊断卡片宽度（稍宽）
const ch = H * 0.75;                     // 卡片高度
const cy = 8;                          // 卡片顶部偏移

// ===== 比值卡片生成函数 =====
function ratioCard(x, label, ratioVal, code) {
  const col = codeColor(code);
  return {
    type: 'group', x, y: cy,
    children: [
      // 卡片背景
      {
        type: 'rect',
        shape: { x: 0, y: 20, width: cw, height: ch, r: 10 },
        style: { fill: cardBg, stroke: border, lineWidth: 1.5 }
      },

      // 比值名称（如 CH4 / H2）
      {
        type: 'text',
        style: {
          x: cw / 2, y: ch * 0.25, text: label,
          textAlign: 'center', fill: textSub,
          font: '15px sans-serif'
        }
      },               // ← 标签字体大小

      // 比值数值
      {
        type: 'text',
        style: {
          x: cw / 2, y: ch * 0.45, text: ratioVal.toFixed(4),
          textAlign: 'center', fill: textMain,
          font: 'bold 28px "Courier New", monospace'
        }
      },  // ← 数值字体大小

      // "编码"小标签
      {
        type: 'text',
        style: {
          x: cw / 2, y: ch * 0.65, text: '编  码',
          textAlign: 'center', fill: textSub,
          font: '13px sans-serif'
        }
      },               // ← 编码标签字体大小

      // 编码色块背景
      {
        type: 'rect',
        shape: { x: cw / 2 - 22, y: ch * 0.75, width: 44, height: 36, r: 6 },
        style: { fill: col + '33', stroke: col, lineWidth: 2 }
      },

      // 编码数字（0 / 1 / 2）
      {
        type: 'text',
        style: {
          x: cw / 2, y: ch * 0.75 + ch * 0.04, text: String(code),
          textAlign: 'center', fill: col,
          font: 'bold 22px sans-serif'
        }
      },          // ← 编码数字字体大小
    ]
  };
}

// ===== 拼装最终 ECharts option =====
const x1 = pad;
const x2 = x1 + cw + pad;
const x3 = x2 + cw + pad;
const x4 = x3 + cw + pad;

return {
  backgroundColor: 'transparent',
  graphic: [
    // 三个比值卡片
    ratioCard(x1, 'CH4 / H2', r1, c1),
    ratioCard(x2, 'C2H2 / C2H4', r2, c2),
    ratioCard(x3, 'C2H4 / C2H6', r3, c3),

    // 诊断结果卡片
    {
      type: 'group', x: x4, y: cy,
      children: [
        // 卡片背景
        {
          type: 'rect',
          shape: { x: 0, y: 20, width: dw, height: ch, r: 10 },
          style: { fill: fault.color + '1a', stroke: fault.color, lineWidth: 2.5 }
        },

        // "诊断结果"标签
        {
          type: 'text',
          style: {
            x: dw / 2, y: ch * 0.20, text: '诊 断 结 果',
            textAlign: 'center', fill: textSub,
            font: '15px sans-serif'
          }
        },              // ← 标签字体大小

        // 故障类型名称
        {
          type: 'text',
          style: {
            x: dw / 2, y: ch * 0.35, text: fault.name,
            textAlign: 'center', fill: fault.color,
            font: 'bold 28px sans-serif'
          }
        },         // ← 故障名称字体大小

        // 编码组合
        {
          type: 'text',
          style: {
            x: dw / 2, y: ch * 0.60,
            text: `编码组合  [ ${c1},  ${c2},  ${c3} ]`,
            textAlign: 'center', fill: textSub,
            font: '14px "Courier New", monospace'
          }
        }, // ← 编码组合字体大小

        // 分隔线
        {
          type: 'line',
          shape: { x1: dw * 0.12, y1: ch * 0.72, x2: dw * 0.88, y2: ch * 0.72 },
          style: { stroke: border, lineWidth: 1 }
        },

        // 气体原始值（第一行）
        {
          type: 'text',
          style: {
            x: dw / 2, y: ch * 0.78,
            text: `H2:${H2.toFixed(1)}  CH4:${CH4.toFixed(1)}  C2H6:${C2H6.toFixed(1)}`,
            textAlign: 'center', fill: textSub,
            font: '13px monospace'
          }
        },               // ← 原始值字体大小

        // 气体原始值（第二行）
        {
          type: 'text',
          style: {
            x: dw / 2, y: ch * 0.90,
            text: `C2H2:${C2H2.toFixed(2)}  C2H4:${C2H4.toFixed(1)}`,
            textAlign: 'center', fill: textSub,
            font: '13px monospace'
          }
        },               // ← 原始值字体大小
      ]
    },
  ]
};

